package main

import (
	"encoding/json"
	"log"
	"net"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/apis"
	"github.com/pocketbase/pocketbase/core"
	"golang.org/x/time/rate"
)

// ipLimiter holds a rate limiter and the last time it was seen for a given IP.
type ipLimiter struct {
	limiter  *rate.Limiter
	lastSeen time.Time
}

// rateLimiterStore manages per-IP rate limiters.
type rateLimiterStore struct {
	mu       sync.Mutex
	limiters map[string]*ipLimiter
	// r is the token replenishment rate (tokens per second).
	r rate.Limit
	// b is the burst size (maximum tokens in the bucket).
	b int
}

func newRateLimiterStore(r rate.Limit, b int) *rateLimiterStore {
	store := &rateLimiterStore{
		limiters: make(map[string]*ipLimiter),
		r:        r,
		b:        b,
	}
	// Periodically clean up stale entries.
	go store.cleanupLoop()
	return store
}

// getLimiter returns (or creates) the rate limiter for the given IP.
func (s *rateLimiterStore) getLimiter(ip string) *rate.Limiter {
	s.mu.Lock()
	defer s.mu.Unlock()

	entry, ok := s.limiters[ip]
	if !ok {
		entry = &ipLimiter{
			limiter: rate.NewLimiter(s.r, s.b),
		}
		s.limiters[ip] = entry
	}
	entry.lastSeen = time.Now()
	return entry.limiter
}

// cleanupLoop removes IP entries that have not been seen for more than 2 minutes.
func (s *rateLimiterStore) cleanupLoop() {
	ticker := time.NewTicker(2 * time.Minute)
	defer ticker.Stop()
	for range ticker.C {
		s.mu.Lock()
		for ip, entry := range s.limiters {
			if time.Since(entry.lastSeen) > 2*time.Minute {
				delete(s.limiters, ip)
			}
		}
		s.mu.Unlock()
	}
}

// signupRequest is the expected JSON body for the custom signup route.
type signupRequest struct {
	Email           string `json:"email"`
	Password        string `json:"password"`
	PasswordConfirm string `json:"passwordConfirm"`
}

func main() {
	app := pocketbase.New()

	// Rate limiter: 5 requests per minute per IP.
	// Using a token-bucket: refill at 5/60 tokens per second, burst of 5.
	store := newRateLimiterStore(rate.Every(time.Minute/5), 5)

	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		// Serves static files from the provided public dir (if exists).
		se.Router.GET("/{path...}", apis.Static(os.DirFS("./pb_public"), false))

		// Custom signup route with per-IP rate limiting.
		se.Router.POST("/api/custom_signup", func(e *core.RequestEvent) error {
			// --- Rate limiting ---
			// Extract the client IP, stripping the port if present.
			remoteAddr := e.Request.RemoteAddr
			ip, _, err := net.SplitHostPort(remoteAddr)
			if err != nil {
				// Fallback: use the raw address.
				ip = remoteAddr
			}
			// Honour X-Forwarded-For when running behind a proxy.
			if forwarded := e.Request.Header.Get("X-Forwarded-For"); forwarded != "" {
				ip = forwarded
			}

			limiter := store.getLimiter(ip)
			if !limiter.Allow() {
				return e.JSON(http.StatusTooManyRequests, map[string]string{
					"message": "rate limit exceeded – try again later",
				})
			}

			// --- Parse request body ---
			var body signupRequest
			if err := json.NewDecoder(e.Request.Body).Decode(&body); err != nil {
				return e.JSON(http.StatusBadRequest, map[string]string{
					"message": "invalid JSON body",
				})
			}

			if body.Email == "" || body.Password == "" || body.PasswordConfirm == "" {
				return e.JSON(http.StatusBadRequest, map[string]string{
					"message": "email, password, and passwordConfirm are required",
				})
			}

			if body.Password != body.PasswordConfirm {
				return e.JSON(http.StatusBadRequest, map[string]string{
					"message": "password and passwordConfirm do not match",
				})
			}

			// --- Create user record ---
			collection, err := app.FindCollectionByNameOrId("users")
			if err != nil {
				return e.JSON(http.StatusInternalServerError, map[string]string{
					"message": "could not find users collection",
				})
			}

			record := core.NewRecord(collection)
			record.Set("email", body.Email)
			record.Set("password", body.Password)
			record.Set("passwordConfirm", body.PasswordConfirm)

			if err := app.Save(record); err != nil {
				return e.JSON(http.StatusBadRequest, map[string]string{
					"message": err.Error(),
				})
			}

			return e.JSON(http.StatusCreated, map[string]any{
				"id":    record.Id,
				"email": record.GetString("email"),
			})
		})

		return se.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

